// Split multiple uploaded files into separate n8n items.
// Each output item has: { json: { ...metadata }, binary: { data: <file> } }
// This node detects the source and normalizes to a single shape downstream.

const items = $input.all();
const results = [];

for (const item of items) {
  const binary = item.binary || {};
  const j = item.json || {};

  // Detect source
  const isGmail = !!(j.subject || j.from || j.labelIds);
  const isWhatsApp = !!(j.payload && j.payload.media);
  const isTelegram = !!(j.message && (j.message.photo || j.message.document));
  const source = isTelegram ? 'telegram' : (isWhatsApp ? 'whatsapp' : (isGmail ? 'email' : 'upload'));

  const senderName = isTelegram
    ? (j.message.from?.first_name || 'Telegram')
    : isWhatsApp
      ? (j.payload._data?.pushName || 'WhatsApp')
      : isGmail
        ? (typeof j.from === 'object' ? j.from.emailAddress : j.from) || 'Gmail'
        : 'Upload';

  const senderPhone = isWhatsApp
    ? (j.payload._data?.key?.remoteJidAlt || j.payload.from || '').replace(/@.*/, '')
    : isTelegram
      ? String(j.message.from?.id || '')
      : isGmail
        ? (typeof j.from === 'object' ? j.from.emailAddress : j.from) || ''
        : '';

  const chatId = isTelegram
    ? String(j.message.chat?.id || '')
    : isWhatsApp
      ? (j.payload.from || '')
      : isGmail
        ? (j.subject || '')
        : 'upload';

  const keys = Object.keys(binary);
  if (keys.length === 0) continue;

  for (const key of keys) {
    const file = binary[key];
    if (!file) continue;

    const mimeType = file.mimeType || '';
    const fileName = file.fileName || (isWhatsApp ? (j.payload.media?.filename || 'unknown') : 'unknown');
    const ext = (fileName.split('.').pop() || '').toLowerCase();
    const isPdf = mimeType.includes('pdf') || ext === 'pdf';

    // Accept only supported types
    const supportedImageExts = ['jpg', 'jpeg', 'png', 'gif', 'bmp', 'tiff', 'webp'];
    const isImage = mimeType.startsWith('image/') || supportedImageExts.includes(ext);
    if (!isPdf && !isImage) continue;

    results.push({
      json: {
        is_pdf: isPdf,
        mime_type: mimeType,
        file_name: fileName,
        source,
        sender_name: senderName,
        sender_phone: senderPhone,
        chat_id: chatId,
      },
      // Keep the binary under a predictable key 'data' so downstream nodes work uniformly.
      binary: { data: file },
    });
  }
}

if (results.length === 0) {
  // No files found — return empty array so downstream short-circuits.
  return [];
}

return results;

// Google Vision OCR for PDFs — tries files:annotate first, falls back to images:annotate
const API_KEY = 'AIzaSyD2cs8yuO_9JVNqKUPlF3TyOd1acwPBGpU';
const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  let base64 = item.json.data || '';
  if (base64.includes(',')) base64 = base64.split(',').pop();

  const fileName = item.json.file_name || '';
  const senderName = item.json.sender_name || '';
  const senderPhone = item.json.sender_phone || '';

  let fullText = '';
  let pagesProcessed = 0;
  let ocrMethod = 'failed';

  const MAX_PAGES_PER_CALL = 5;
  const MAX_TOTAL_PAGES = 50;

  try {
    // Attempt 1: PDF multi-page via files:annotate
    let hasMore = true;
    for (let startPage = 1; startPage <= MAX_TOTAL_PAGES && hasMore; startPage += MAX_PAGES_PER_CALL) {
      const pages = [];
      for (let p = startPage; p < startPage + MAX_PAGES_PER_CALL && p <= MAX_TOTAL_PAGES; p++) pages.push(p);

      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://vision.googleapis.com/v1/files:annotate?key=' + API_KEY,
        headers: { 'Content-Type': 'application/json' },
        body: {
          requests: [{
            inputConfig: { content: base64, mimeType: 'application/pdf' },
            features: [{ type: 'DOCUMENT_TEXT_DETECTION' }],
            pages
          }]
        },
        json: true,
        timeout: 30000
      });

      const outer = resp.responses || [];
      let batchPages = 0;
      for (const r of outer) {
        const pageResponses = r.responses || [];
        batchPages = pageResponses.length;
        for (const page of pageResponses) {
          if (page.fullTextAnnotation?.text) fullText += page.fullTextAnnotation.text + '\n';
          pagesProcessed++;
        }
      }
      if (batchPages < MAX_PAGES_PER_CALL) hasMore = false;
    }
    if (fullText.trim().length > 20) ocrMethod = 'google_vision_pdf';
  } catch (e1) {
    // Attempt 2: treat PDF first page as image
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://vision.googleapis.com/v1/images:annotate?key=' + API_KEY,
        headers: { 'Content-Type': 'application/json' },
        body: { requests: [{ image: { content: base64 }, features: [{ type: 'DOCUMENT_TEXT_DETECTION' }] }] },
        json: true,
        timeout: 30000
      });
      const t = resp.responses?.[0]?.fullTextAnnotation?.text;
      if (t) { fullText = t; pagesProcessed = 1; ocrMethod = 'google_vision_image_fallback'; }
    } catch (e2) {
      fullText = `[OCR failed for PDF: ${fileName}]\nSender: ${senderName} ${senderPhone}`;
      ocrMethod = 'failed';
    }
  }

  results.push({
    json: {
      raw_text: fullText.trim(),
      file_type: 'pdf',
      ocr_method: ocrMethod,
      pages_processed: pagesProcessed,
      file_name: fileName,
      source: item.json.source,
      sender_name: senderName,
      sender_phone: senderPhone,
      chat_id: item.json.chat_id
    },
    binary: item.binary || {}
  });
}

return results;

// Google Vision OCR for single images
const API_KEY = 'AIzaSyD2cs8yuO_9JVNqKUPlF3TyOd1acwPBGpU';
const items = $input.all();
const results = [];

for (const item of items) {
  let base64 = item.json.data || '';
  if (base64.includes(',')) base64 = base64.split(',').pop();

  let text = '';
  let ocrMethod = 'failed';

  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://vision.googleapis.com/v1/images:annotate?key=' + API_KEY,
      headers: { 'Content-Type': 'application/json' },
      body: { requests: [{ image: { content: base64 }, features: [{ type: 'DOCUMENT_TEXT_DETECTION' }] }] },
      json: true,
      timeout: 30000
    });
    const t = resp.responses?.[0]?.fullTextAnnotation?.text || resp.responses?.[0]?.textAnnotations?.[0]?.description;
    if (t) { text = t; ocrMethod = 'google_vision'; }
  } catch (e) {
    text = `[OCR failed for image: ${item.json.file_name}]`;
    ocrMethod = 'failed';
  }

  results.push({
    json: {
      raw_text: text.trim(),
      file_type: 'image',
      ocr_method: ocrMethod,
      file_name: item.json.file_name,
      source: item.json.source,
      sender_name: item.json.sender_name,
      sender_phone: item.json.sender_phone,
      chat_id: item.json.chat_id
    },
    binary: item.binary || {}
  });
}

return results;

