// Fetch suppliers for the matched business (or return empty list).
const SB = 'https://db.amazpenbiz.co.il';
const SK = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpYXQiOjE3NzExNTM2NTMsImV4cCI6MTg5MzQ1NjAwMCwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlzcyI6InN1cGFiYXNlIn0.jO_qu5aNUaOZ0YBdfW5MbzdML-csEU9QkqoTGAx5yzY';
const authHeaders = { apikey: SK, Authorization: 'Bearer ' + SK };

const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const ai = item.json.output || item.json;
  const ctx = $('Build Context').all()[i]?.json || {};
  const businessId = (ai.business_id || '').trim();

  let suppliersMd = '| ID | Name | Tax ID |\n|---|---|---|\n';
  if (businessId) {
    try {
      const suppliers = await this.helpers.httpRequest({
        method: 'GET',
        url: SB + '/rest/v1/suppliers?select=id,name,tax_id&business_id=eq.' + businessId + '&is_active=eq.true&deleted_at=is.null&order=name.asc',
        headers: authHeaders,
        json: true
      });
      for (const s of suppliers) {
        suppliersMd += `| ${s.id} | ${s.name || ''} | ${s.tax_id || ''} |\n`;
      }
    } catch (e) {}
  }

  results.push({
    json: {
      text: ctx.text,
      raw_text: ctx.raw_text,
      source: ctx.source,
      file_type: ctx.file_type,
      file_name: ctx.file_name,
      ocr_method: ctx.ocr_method,
      sender_name: ctx.sender_name,
      sender_phone: ctx.sender_phone,
      chat_id: ctx.chat_id,
      business_id: businessId || null,
      business_name: ai.business_name || '',
      business_tax_id: ai.business_tax_id || '',
      suppliers_markdown: suppliersMd,
      has_matched_business: !!businessId,
      business_context_note: businessId
        ? `The business has already been identified:\n- Business ID: ${businessId}\n- Business Name: ${ai.business_name || ''}\n- Business Tax ID: ${ai.business_tax_id || ''}`
        : 'No business was matched. Extract business_name and business_tax_id from the document text if visible.'
    },
    binary: item.binary || {}
  });
}

return results;

// Prepare storage path + normalize extracted data for DB insertion.
// Restores the file binary from the Split Files node (AI nodes drop binary).
const items = $input.all();
const splitItems = $('Split Files').all();
const results = [];

const typeMap = {
  invoice: 'invoice',
  delivery_note: 'delivery_note',
  credit_note: 'credit_note',
  payment: 'payment',
  receipt: 'payment',
  summary: 'summary',
  daily_entry: 'daily_entry',
  'חשבונית': 'invoice',
  'חשבונית מס': 'invoice',
  'חשבונית מס קבלה': 'invoice',
  'חשבונית עסקה': 'invoice',
  'תעודת משלוח': 'delivery_note',
  'חשבונית זיכוי': 'credit_note',
  'זיכוי': 'credit_note',
  'קבלה': 'payment',
  'אישור תשלום': 'payment',
  'מרכזת': 'summary',
  'ריכוז חשבוניות': 'summary',
  'מילוי יומי': 'daily_entry',
  'רישום יומי': 'daily_entry',
  'דוח יומי': 'daily_entry',
  'נתוני יום': 'daily_entry'
};

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const ai = item.json.output || item.json;
  const ctx = $('Fetch Suppliers').all()[i]?.json || {};
  const fileType = ctx.file_type || 'image';
  const ext = fileType === 'pdf' ? '.pdf' : '.jpg';
  const fileName = `${Date.now()}-${Math.random().toString(36).substring(2, 8)}${ext}`;
  const storagePath = `upload/${fileName}`;
  const contentType = fileType === 'pdf' ? 'application/pdf' : 'image/jpeg';

  let itemsList = [];
  if (Array.isArray(ai.items)) {
    itemsList = ai.items.filter(x => x && x.description);
  } else if (typeof ai.items === 'string' && ai.items.trim()) {
    try { itemsList = JSON.parse(ai.items); } catch (e) { itemsList = []; }
  }

  const businessId = (ai.business_id && String(ai.business_id).trim()) || ctx.business_id || null;

  // Restore binary from Split Files by matching file_name (safer than $itemIndex).
  let fileBinary = {};
  const targetName = ctx.file_name;
  if (targetName) {
    const match = splitItems.find(s => s.json?.file_name === targetName);
    if (match?.binary?.data) fileBinary = { data: match.binary.data };
  }
  // Fallback to index if name match failed.
  if (!fileBinary.data && splitItems[i]?.binary?.data) {
    fileBinary = { data: splitItems[i].binary.data };
  }

  const dt = (ai.document_type || '').toLowerCase().trim();

  results.push({
    json: {
      storagePath,
      contentType,
      fileName,
      fileType,
      document_type: typeMap[dt] || typeMap[ai.document_type] || 'invoice',
      supplier_name: ai.supplier_name || '',
      supplier_tax_id: ai.supplier_tax_id || '',
      supplier_id: (ai.supplier_id && String(ai.supplier_id).trim()) || null,
      business_id: businessId,
      business_name: ai.business_name || ctx.business_name || '',
      business_tax_id: ai.business_tax_id || ctx.business_tax_id || '',
      document_number: ai.document_number || '',
      date: ai.date || null,
      amount_before_vat: ai.amount_before_vat || 0,
      vat_amount: ai.vat_amount || 0,
      amount_after_vat: ai.amount_after_vat || 0,
      items: itemsList,
      raw_text: ctx.raw_text || '',
      ocr_method: ctx.ocr_method || 'unknown',
      source: ctx.source || 'upload',
      chat_id: ctx.chat_id || '',
      sender_name: ctx.sender_name || '',
      sender_phone: ctx.sender_phone || ''
    },
    binary: fileBinary
  });
}

return results;

// Insert into ocr_documents, ocr_extracted_data, ocr_extracted_line_items.
const SB = 'https://db.amazpenbiz.co.il';
const SK = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpYXQiOjE3NzExNTM2NTMsImV4cCI6MTg5MzQ1NjAwMCwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlzcyI6InN1cGFiYXNlIn0.jO_qu5aNUaOZ0YBdfW5MbzdML-csEU9QkqoTGAx5yzY';
const h = { 'Content-Type': 'application/json', apikey: SK, Authorization: 'Bearer ' + SK, Prefer: 'return=representation' };

const items = $input.all();
const results = [];

// Validation helpers
const validUUID = (v) => {
  if (!v || typeof v !== 'string') return null;
  v = v.trim();
  if (!v || v === 'null' || v === 'undefined' || v === 'N/A') return null;
  return /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(v) ? v : null;
};
const validDate = (v) => {
  if (!v || typeof v !== 'string') return null;
  v = v.trim();
  if (!v || v === 'null' || v === 'N/A' || v === 'undefined') return null;
  if (/^\d{4}-\d{2}-\d{2}$/.test(v)) return v;
  const m = v.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (m) return `${m[3]}-${m[2]}-${m[1]}`;
  return null;
};
const validNum = (v) => {
  if (v === null || v === undefined || v === '' || v === 'N/A') return 0;
  const n = Number(v);
  return isNaN(n) ? 0 : n;
};
const validText = (v) => (!v || typeof v !== 'string') ? '' : v.trim();

for (let i = 0; i < items.length; i++) {
  const prep = $('Prepare Upload').all()[i]?.json;
  if (!prep) {
    results.push({ json: { success: false, error: 'Missing prepare data' } });
    continue;
  }

  const storagePath = prep.storagePath;
  const imageUrl = `${SB}/storage/v1/object/public/ocr-documents/${storagePath}`;
  const ocrEngine = prep.ocr_method || (prep.fileType === 'pdf' ? 'pdf_extract' : 'google_vision');

  try {
    const docBody = {
      source: validText(prep.source) || 'upload',
      image_url: imageUrl,
      image_storage_path: storagePath,
      file_type: validText(prep.fileType) || 'image',
      status: 'pending',
      document_type: validText(prep.document_type) || 'invoice',
      ocr_engine: ocrEngine,
      ocr_processed_at: new Date().toISOString()
    };
    const ocrFailed = prep.ocr_method === 'failed' || (prep.raw_text || '').trim().length < 30;
    const biz = ocrFailed ? null : validUUID(prep.business_id);
    if (biz) docBody.business_id = biz;
    if (validText(prep.chat_id)) docBody.source_chat_id = validText(prep.chat_id);
    if (validText(prep.sender_name)) docBody.source_sender_name = validText(prep.sender_name);
    if (validText(prep.sender_phone)) docBody.source_sender_phone = validText(prep.sender_phone);

    const d1 = await this.helpers.httpRequest({
      method: 'POST',
      url: SB + '/rest/v1/ocr_documents',
      headers: h,
      body: docBody,
      json: true
    });
    const docId = Array.isArray(d1) ? d1[0]?.id : d1.id;
    if (!docId) {
      results.push({ json: { success: false, error: 'Failed to insert document', details: d1 } });
      continue;
    }

    const extBody = {
      document_id: docId,
      raw_text: validText(prep.raw_text),
      supplier_name: validText(prep.supplier_name),
      supplier_tax_id: validText(prep.supplier_tax_id),
      document_number: validText(prep.document_number),
      subtotal: validNum(prep.amount_before_vat),
      vat_amount: validNum(prep.vat_amount),
      total_amount: validNum(prep.amount_after_vat),
      extraction_metadata: {
        items: prep.items || [],
        business_name: validText(prep.business_name),
        business_tax_id: validText(prep.business_tax_id),
        business_id: validUUID(prep.business_id)
      }
    };
    const docDate = validDate(prep.date);
    if (docDate) extBody.document_date = docDate;
    const suppId = validUUID(prep.supplier_id);
    if (suppId) extBody.matched_supplier_id = suppId;

    const d2 = await this.helpers.httpRequest({
      method: 'POST',
      url: SB + '/rest/v1/ocr_extracted_data',
      headers: h,
      body: extBody,
      json: true
    });
    const extractedDataId = Array.isArray(d2) ? d2[0]?.id : d2.id;

    let lineItemsCount = 0;
    if (extractedDataId && Array.isArray(prep.items) && prep.items.length > 0) {
      for (let idx = 0; idx < prep.items.length; idx++) {
        const it = prep.items[idx];
        if (!it || !it.description) continue;
        try {
          await this.helpers.httpRequest({
            method: 'POST',
            url: SB + '/rest/v1/ocr_extracted_line_items',
            headers: h,
            body: {
              extracted_data_id: extractedDataId,
              line_number: idx + 1,
              description: validText(it.description),
              quantity: validNum(it.quantity),
              unit_price: validNum(it.unit_price),
              total: validNum(it.total)
            },
            json: true
          });
          lineItemsCount++;
        } catch (e) {}
      }
    }

    results.push({
      json: {
        success: true,
        document_id: docId,
        image_url: imageUrl,
        source: prep.source,
        business_id: biz,
        supplier_id: suppId,
        line_items_saved: lineItemsCount,
        ocr_method: prep.ocr_method
      }
    });
  } catch (err) {
    results.push({
      json: {
        success: false,
        error: err.message,
        source: prep.source || 'unknown',
        fileName: prep.fileName || 'unknown',
        supplier_name: prep.supplier_name || ''
      }
    });
  }
}

return results;
